// NewBluetoothHeadsetStub creates a server-side IBluetoothHeadset wrapping the given
// server implementation. The returned value satisfies IBluetoothHeadset
// and can be passed to proxy methods; its AsBinder() returns a
// *binder.StubBinder that is auto-registered with the binder
// driver on first use.
func NewBluetoothHeadsetStub(
	impl IBluetoothHeadsetServer,
) IBluetoothHeadset {
	wrapper := &bluetoothHeadsetStubWrapper{impl: impl}
	stub := &BluetoothHeadsetStub{Impl: wrapper}
	wrapper.stubBinder = binder.NewStubBinder(stub)
	return wrapper
}
